UPDATE NMCP_CUST_POINT_GIVE_TGT_BAS 
SET POINT_CUST_SEQ = #{pointCustSeq} -- 포인트고객일련번호
    , POINT_GIVE_CPLT_YN = #{pointGiveCpltYn} -- 포인트지급완료여부
    , POINT_GIVE_CPLT_DATE = #{pointGiveCpltDate} -- 포인트지급완료일자
	,AMD_IP = #{amdIp}
	,AMD_DT = SYSDATE
	,AMD_ID = #{amdId}
WHERE CUST_POINT_GIVE_TGT_SEQ = #{custPointGiveTgtSeq}
